Let's start by identifying the key components and functionalities required for a Checkers (Draughts) game:

1. **Board Representation**: A 2D list to represent the 8x8 board.
2. **Piece Class**: Represents each piece with attributes like color, type, and whether it is kinged.
3. **Game Class**: Manages the game state, including player turns, move validation, capturing, and win/draw detection.
4. **Move Validation**: Ensures that moves are legal according to Checkers rules.
5. **Board Display**: Function to print the board in a readable format.

Let's begin by implementing these components step-by-step.

### Step 1: Define the Piece Class

We need a class to represent each piece. Each piece has attributes for color, type (normal or king), and position on the board.

```json
{"name": "save_file", "arguments": {"path": "Piece.py", "content": "class Piece:
    def __init__(self, color, position=None):
        self.color = color
        self.position = position
        self.type = 'normal'

    def king(self):
        self.type = 'king'

    def get_color_char(self):
        return 'b' if self.color == 'black' else 'r'

    def __str__(self):
        return f'{self.get_color_char()}{"K" if self.type == "king" else ""}'}}
```

### Step 2: Define the Game Class

The Game class will manage the game state, including player turns, move validation, capturing, and win/draw detection.

```json
{"name": "save_file", "arguments": {"path": "Game.py", "content": "from Piece import Piece

class Game:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.current_player = 'black'
        self.initialize_board()

    def initialize_board(self):
        positions = [(i, j) for i in range(8) for j in range(8) if (i + j) % 2 == 1]
        black_positions = [pos for pos in positions if pos[0] < 3]
        red_positions = [pos for pos in positions if pos[0] > 4]

        for pos in black_positions:
            self.board[pos[0]][pos[1]] = Piece('black', pos)
        for pos in red_positions:
            self.board[pos[0]][pos[1]] = Piece('red', pos)

    def print_board(self):
        for row in self.board:
            print(' '.join(str(piece) if piece else '-' for piece in row))

    def get_piece_at(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece_at(from_pos)
        if piece and piece.color == self.current_player:
            self.board[to_pos[0]][to_pos[1]] = piece
            piece.position = to_pos
            self.board[from_pos[0]][from_pos[1]] = None
            self.current_player = 'red' if self.current_player == 'black' else 'black'

    def is_valid_move(self, from_pos, to_pos):
        piece = self.get_piece_at(from_pos)
        if not piece or piece.color != self.current_player:
            return False

        dx, dy = abs(to_pos[0] - from_pos[0]), abs(to_pos[1] - from_pos[1])
        if (dx, dy) not in [(1, 1), (2, 2)] or self.board[to_pos[0]][to_pos[1]] is not None:
            return False

        if dx == 2 and piece.type == 'normal':
            mid_piece = self.get_piece_at(((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2))
            if not mid_piece or mid_piece.color != self.current_player:
                return False
        return True

    def check_win(self):
        black_pieces = sum(row.count(Piece('black')) for row in self.board)
        red_pieces = sum(row.count(Piece('red')) for row in self.board)
        if black_pieces == 0 or not any(game.is_valid_move(from_pos, (i, j)) for i in range(8) for j in range(8) for from_pos in [(x, y) for x in range(8) for y in range(8) if self.get_piece_at((x, y)) and self.get_piece_at((x, y)).color == 'black']):
            return 'Red wins!'
        elif red_pieces == 0 or not any(game.is_valid_move(from_pos, (i, j)) for i in range(8) for j in range(8) for from_pos in [(x, y) for x in range(8) for y in range(8) if self.get_piece_at((x, y)) and self.get_piece_at((x, y)).color == 'red']):
            return 'Black wins!'
        elif black_pieces + red_pieces <= 2:
            return 'Draw!'"}}
```

### Step 3: Main Execution

We need a main function to handle user input and call the game methods.

```json
{"name": "save_file", "arguments": {"path": "main.py", "content": "from Game import Game

def get_move(player):
    move = input(f'Player {player}, enter your move (e.g., A1-B2): ').upper()
    return move

if __name__ == '__main__':
    game = Game()
    while True:
        game.print_board()
        from_pos_str, to_pos_str = get_move(game.current_player)
        if len(from_pos_str) != 2 or len(to_pos_str) != 2:
            print('Invalid move format. Please use A1-B2 format.')
            continue

        from_pos = (8 - int(from_pos_str[1]), ord(from_pos_str[0]) - ord('A'))
        to_pos = (8 - int(to_pos_str[1]), ord(to_pos_str[0]) - ord('A'))

        if not game.is_valid_move(from_pos, to_pos):
            print('Invalid move. Please try again.')
            continue

        game.move_piece(from_pos, to_pos)

        result = game.check_win()
        if result:
            game.print_board()
            print(result)
            break"}}
```

